import boto3

def manage_sns_subscriptions():
    """
    Manages SNS subscriptions by accepting endpoint URLs from user input
    and creating HTTPS subscriptions without validation.
    """
    sns_client = boto3.client('sns')

    # Prompt user for the SNS topic ARN
    topic_arn = input("Enter the SNS Topic ARN: ").strip()

    while True:
        endpoint_url = input(
            "Enter the HTTPS endpoint URL for subscription "
            "(or type 'done' to finish): "
        ).strip()

        if endpoint_url.lower() == 'done':
            break

        if not endpoint_url:
            print("Endpoint URL cannot be empty. Please try again.")
            continue

        try:
            print(f"Attempting to subscribe {endpoint_url} to {topic_arn}...")
            response = sns_client.subscribe(
                TopicArn=topic_arn,
                Protocol='https',
                Endpoint=endpoint_url,
                ReturnSubscriptionArn=True
            )
            subscription_arn = response.get('SubscriptionArn')
            if subscription_arn:
                print(f"Successfully initiated subscription for {endpoint_url}.")
                print(f"Subscription ARN: {subscription_arn}")
                print("Note: The endpoint will need to confirm the subscription.")
            else:
                print(f"Failed to get Subscription ARN for {endpoint_url}. Response: {response}")

        except Exception as e:
            print(f"An error occurred while subscribing {endpoint_url}: {e}")
            print("Please ensure the Topic ARN is correct and your AWS credentials have permission to subscribe.")

    print("Subscription process finished.")

if __name__ == "__main__":
    manage_sns_subscriptions()